#!/usr/bin/env python3
"""Search subgroups generated by subsets of the standard generators for order 1440.

This heuristic looks for subgroups that are generated by some subset of the generators
used to build GSp(4,3). It won't find all subgroups, but it will find any that are
generated by a subset of the standard generators (2^k possibilities, k~9 -> ~512).

Writes artifacts/find_1440_subgroup_candidates.json with any matches.
"""
from __future__ import annotations

import json
from collections import deque
from itertools import combinations
from pathlib import Path

from tools.w33_aut_group_construct import build_points, generate_group, matrix_to_perm

ROOT = Path(__file__).resolve().parent
ART = ROOT / "artifacts"
ART.mkdir(exist_ok=True)


def closure_generated_by(gens_subset, degree):
    identity = tuple(range(degree))
    closure = {identity}
    q = deque([identity])
    while q:
        h = q.popleft()
        for g in gens_subset:
            comp = tuple(g[i] for i in h)
            if comp not in closure:
                closure.add(comp)
                q.append(comp)
    return closure


def main():
    pts = build_points()
    degree = len(pts)
    G, perms = generate_group(pts)
    k = len(perms)
    print("Generator count:", k)

    candidates = []
    seen_orders = {}
    for r in range(1, k + 1):
        for idxs in combinations(range(k), r):
            gens_subset = [perms[i] for i in idxs]
            closure = closure_generated_by(gens_subset, degree)
            order = len(closure)
            seen_orders.setdefault(order, 0)
            seen_orders[order] += 1
            if order == 1440:
                # compute orbit sizes on points
                orbits = []
                seen = set()
                for i in range(degree):
                    if i in seen:
                        continue
                    orb = {g[i] for g in closure}
                    for x in orb:
                        seen.add(x)
                    orbits.append(len(orb))
                candidates.append(
                    {
                        "gens_idx": idxs,
                        "order": order,
                        "orbits": sorted(orbits, reverse=True),
                    }
                )
    out = {"seen_order_counts": seen_orders, "candidates": candidates}
    (ART / "find_1440_subgroup_candidates.json").write_text(
        json.dumps(out, indent=2), encoding="utf-8"
    )
    print("Wrote", ART / "find_1440_subgroup_candidates.json")


if __name__ == "__main__":
    main()
